// MAIN PROVIDERS COMPONENT
// ============================================

export interface ProvidersProps {
  children: React.ReactNode;
  /**
   * NextAuth session (optional, for SSR)
   */
  session?: any;
  /**
   * Default theme
   */
  defaultTheme?: "light" | "dark" | "system";
  /**
   * Enable analytics
   */
  enableAnalytics?: boolean;
  /**
   * Show React Query devtools
   */
  showQueryDevtools?: boolean;
}

/**
 * Providers Component
 *
 * Wraps the application with all necessary context providers.
 * Should be used in the root layout.
 *
 * @example
 * // In app/layout.tsx
 * import { Providers } from "@/components/providers";
 *
 * export default function RootLayout({ children }) {
 *   return (
 *     <html>
 *       <body>
 *         <Providers>{children}</Providers>
 *       </body>
 *     </html>
 *   );
 * }
 */
export function Providers({
  children,
  session,
  defaultTheme = "system",
  enableAnalytics = true,
  showQueryDevtools = process.env.NODE_ENV === "development",
}: ProvidersProps) {
  // Get or create query client
  const queryClient = getQueryClient();

  return (
    <ErrorBoundary>
      <SessionProvider session={session}>
        <QueryClientProvider client={queryClient}>
          <ThemeProvider defaultTheme={defaultTheme}>
            <AnalyticsProvider enabled={enableAnalytics}>
              <NotificationProvider>
                <CartProvider>
                  {children}
                </CartProvider>
              </NotificationProvider>
            </AnalyticsProvider>
          </ThemeProvider>
          {showQueryDevtools && (
            <ReactQueryDevtools initialIsOpen={false} position="bottom" />
          )}
        </QueryClientProvider>
      </SessionProvider>
    </ErrorBoundary>
  );
}

